@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p>Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar">
        <span><strong>Total:</strong> @allTasks.Count</span>
        <span><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span><strong>Overdue:</strong> @allTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="search-bar">
        <input type="text" placeholder="Search tasks by title..." @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="board">
        @foreach (var column in columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            <div class="board-column">
                <h3>@column (@tasks.Count)</h3>

                @foreach (var task in tasks)
                {
                    <div class="task-card">
                        <div class="task-title">@task.Title</div>
                        <div class="task-assignee">@task.Assignee</div>
                        <span class="priority-badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                        <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                        <div class="task-actions">
                            @if (column != columns[0])
                            {
                                <button @onclick="() => MoveTask(task, -1)">Move Left</button>
                            }
                            @if (column != columns[^1])
                            {
                                <button @onclick="() => MoveTask(task, 1)">Move Right</button>
                            }
                        </div>
                    </div>
                }

                @if (addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" placeholder="Title" @bind="newTitle" />
                        <input type="text" placeholder="Assignee" @bind="newAssignee" />
                        <select @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" @bind="newDueDate" />
                        <div class="form-buttons">
                            <button @onclick="SaveTask">Save</button>
                            <button @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="add-task-btn" @onclick="() => StartAdd(column)">Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    private string[] columns = { "To Do", "In Progress", "Done" };

    // Add task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchQuery) ||
                         t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private string GetPriorityClass(string priority) => priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = Array.IndexOf(columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            allTasks = allTasks.Select(t => t.Id == task.Id ? task with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelAdd()
    {
        addingToColumn = null;
    }

    private async Task SaveTask()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || addingToColumn is null) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            allTasks.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

